#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int best=0, cur=0, x;
        for(int i=0;i<N;++i){
            scanf("%d",&x);
            if(x==1){
                ++cur;
                if(cur>best) best=cur;
            }else{
                cur=0;
            }
        }
        printf("%d\n",best);
    }
    return 0;
}

