import sys
def solve_one(arr):
    cur=best=0
    for v in arr:
        if v==1:
            cur+=1
            if cur>best: best=cur
        else:
            cur=0
    return best

def main():
    data=list(map(int,sys.stdin.read().strip().split()))
    if not data: return
    idx=0
    T=data[idx]; idx+=1
    out=[]
    for _ in range(T):
        N=data[idx]; idx+=1
        arr=data[idx:idx+N]; idx+=N
        out.append(str(solve_one(arr)))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()

